import { describe, expect, it } from "vitest";
import { buildStudioSessionUrl, DEFAULT_STUDIO_PATH, resolveStudioInitialPath, } from "./studioUrl.js";
describe("resolveStudioInitialPath", () => {
    it("passes a valid studio route through unchanged", () => {
        expect(resolveStudioInitialPath("/studio/experiments")).toBe("/studio/experiments");
    });
    it("preserves a valid route's query string", () => {
        const signIn = "/studio/sign-in?redirect_url=%2Fstudio&session=abc";
        expect(resolveStudioInitialPath(signIn)).toBe(signIn);
    });
    it("falls back to the studio home for a disallowed route", () => {
        expect(resolveStudioInitialPath("/studio/admin")).toBe(DEFAULT_STUDIO_PATH);
        expect(resolveStudioInitialPath("/traces")).toBe(DEFAULT_STUDIO_PATH);
    });
    it("falls back to the studio home for empty input", () => {
        expect(resolveStudioInitialPath()).toBe(DEFAULT_STUDIO_PATH);
        expect(resolveStudioInitialPath(null)).toBe(DEFAULT_STUDIO_PATH);
        expect(resolveStudioInitialPath("")).toBe(DEFAULT_STUDIO_PATH);
    });
});
describe("buildStudioSessionUrl", () => {
    const serviceUrl = "https://test.invalid";
    it("appends a session param when none is present", () => {
        expect(buildStudioSessionUrl({ serviceUrl, path: "/studio", sessionId: "s-1" })).toBe("https://test.invalid/studio?session=s-1");
    });
    it("uses & as the separator when the path already has a query string", () => {
        expect(buildStudioSessionUrl({
            serviceUrl,
            path: "/studio/experiments?testRunIds=a,b",
            sessionId: "s-1",
        })).toBe("https://test.invalid/studio/experiments?testRunIds=a,b&session=s-1");
    });
    it("is idempotent when the path already carries a session param", () => {
        const path = "/studio/sign-in?session=existing";
        expect(buildStudioSessionUrl({ serviceUrl, path, sessionId: "s-1" })).toBe(`https://test.invalid${path}`);
    });
    it("encodes the session id", () => {
        expect(buildStudioSessionUrl({
            serviceUrl,
            path: "/studio",
            sessionId: "a b/c",
        })).toBe("https://test.invalid/studio?session=a%20b%2Fc");
    });
});
